var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"제기랄......","JPN":"畜生ォ……","ENG":"Damn it...","TWN":"可惡……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"제기랄! 제기랄! 제기랄! 제기랄! 제기랄! 제기랄! 제기랄!","JPN":"畜生ォ！　畜生ォ！　畜生ォ！　畜生ォ！　畜生ォ！\\n畜生ォ！　畜生ォ！","ENG":"Damn it! Damn it! Damn it! Damn it! Damn it! Damn it! Damn it!","TWN":"可惡！可惡！可惡！可惡！可惡！可惡！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"사도랍시고 무게는 있는 대로 잡더니 겨우 한 명에게 박살 나 버려?!","JPN":"使徒だからってあんなに威張り散らしておいて、\\nたった一人に撃破されたの！？","ENG":"She went all Shakespeare on us with her Apostle talk, only to let one Closer smash her to bits like that?","TWN":"什麼破使徒，竟然被一個人打爆了？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"저딴 걸 믿은 내가 멍청이였지!","JPN":"あんなのを頼りにした私がバカだったわ！","ENG":"I'm the fool for relying on something like that!","TWN":"會相信這種東西的我是個笨蛋！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"날 처박아 둔 곳까지 도망쳐 오다니...... 꽤나 급해진 모양이군, 알렉스?","JPN":"こんなところに放り捨ててくれたと思えば、また逃げ戻ってくるとは……\\nよほど切羽詰まってるようだな？　アレックス。","ENG":"So you've fled all the way to where you've stashed me... Looks like you're getting desperate, Alex.","TWN":"妳竟然逃到了關我的地方……看起來妳也被逼急了呢，雅蕾克絲？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"닥쳐! 애초에 네가 저런 쭉정이와 계약한 게 문제였어!","JPN":"黙りなさい！　そもそもアンタがあんなでくの坊と契約を交わしたのが間違いなのよ！","ENG":"Shut up! You should have never signed a deal with a good-for-nothing loser like that!","TWN":"閉嘴！說到底，都怪妳和那個垃圾定契約！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그 녀석이 죽어버렸으니 너도 끈 떨어진 건 마찬가지야!","JPN":"あいつが死んでしまった以上、\\nもうアンタも拠り所がなくなったのは同じだわ！","ENG":"You're screwed too, since she's dead now!","TWN":"那傢伙現在已經死了，沒有人可以幫妳撐腰了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"사도급 이상의 침식체는 불멸의 존재다.","JPN":"使徒以上の侵食体は不滅の存在だ。","ENG":"Apostles and any other C.O.s beyond them are immortal.","TWN":"使徒級以上的侵蝕體是不滅的存在。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이수연에게 육체를 파괴당하고 클리파 너머로 추방당했지만, 언젠가 힘을 회복해서 다시 돌아오겠지.","JPN":"カナミ・キズナに肉体を破壊され、クリファ次元の彼方へ\\n追放されようと、いつか力を回復してまた戻ってくる。","ENG":"Although her flesh may have been destroyed by Lee Sooyeon and banished beyond the Qlipha, she will recover and return one day.","TWN":"雖然它的肉體被李秀妍破壞，放逐回了逆卡巴拉，但總有一天，它會恢復力量回來的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"계약자인 우리 얘기는 지금도 다 듣고 있을 텐데, 조금은 말조심을 해야 할 것 같지 않나?","JPN":"契約者である我々の発言は今でもすべて筒抜けのはずだ。\\n少しは口を慎むべきだと思わないか？","ENG":"She's probably listening in on contractors like us even now. Perhaps you should choose your words more carefully.","TWN":"她現在應該還在聽我們契約者的對話，妳說話最好還是小心一點喔？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그, 그건...... 그러니까 내 말뜻은 그게 아니라......","JPN":"えっ、その……だから、私が言ったのはそういう意味じゃ……","ENG":"Th-that's... Well, I didn't mean it like that...","TWN":"這、這……所以說，我想說的不是那樣……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"오해하지 마! 그런 뜻은 아니었어!","JPN":"誤解しないでよ！　別に悪気があったわけじゃないの！","ENG":"I hope there's no misunderstanding! I didn't mean it like that!","TWN":"別誤會！我不是那個意思！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그러니까 그 분께는 오해하지 말라고 전달을 좀......","JPN":"だからあの方が誤解なさらないように、あなたの方から話を……","ENG":"So, um, could you tell her that I didn't really mean that?","TWN":"妳能不能替我解釋一下，讓他不要誤會……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"흥. 알겠다. 그 정도야.","JPN":"フン。いいだろう。それくらいなら容易い。","ENG":"Hmpf. Fine. That shouldn't be too hard.","TWN":"哼，好啦，我會啦。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"저, 정말이야?","JPN":"ほ、本当？","ENG":"R-really?","TWN":"真、真的嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그래. 어차피 나도 살아남으려면 도움이 필요하니까.","JPN":"ああ。私とて生き残るためには助力が必要だからな。","ENG":"Yes. I need your help to survive anyways.","TWN":"對，畢竟我想活命，也需要妳的幫忙。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"사도께서 패퇴하긴 했어도 클리파의 봉인이 약해진 건 변하지 않아.","JPN":"使徒が敗退されたとはいえ、\\nクリファ次元の封印は今も弱まったままだ。","ENG":"Although the Apostle has been defeated, the Qlipha's seal remains weakened.","TWN":"雖然使徒大人戰敗了，但逆卡巴拉的封印變弱的事實也沒有改變。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"우리도 그 곳으로 넘어가서 힘을 기르는 게 낫겠지.","JPN":"我々もそこに渡り、力を蓄えるのが得策だろう。","ENG":"We'll be better off going over there and rebuilding our strength.","TWN":"不如我們也去那個地方養精蓄銳吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그거야! 처음부터 그런 현실적인 판단을 내리면 좋았잖아!","JPN":"そう、それよ！　そんなふうにはじめから現実的な判断を\\n下せばよかったじゃない！","ENG":"That's what I'm talking about! See? It would've been much better if you made such realistic decisions from the get-go!","TWN":"就是說啊！如果妳一開始就做出這樣務實的判斷就好了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그러니 날 좀 일으켜 다오.","JPN":"ああ。そのためにも私の手を引いて立たせてくれ。","ENG":"So help me up.","TWN":"所以把我扶起來吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"지금 난 누구 때문에 걷기도 힘들거든.","JPN":"今の私は、誰かさんのおかげで歩くことすらままならないのでな。","ENG":"I can barely walk right now because of you-know-who.","TWN":"我被某人害得連走都不能走了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"크로노스의 잔해에 처박힌 상태로는 사도께 클리파 차원의 입구를 열어달라고 부탁할 수도 없으니까.","JPN":"クロノスの残骸に突っ込まれた状態では、\\n使徒にクリファ次元の入口を開いてくれと願うこともできん。","ENG":"I won't be able to ask the Apostle to open the gate to the Qlipha dimension when I'm stuck in the remains of Chronos.","TWN":"埋在克羅諾斯殘骸裡的狀態下，可沒辦法請使徒打開逆卡巴拉次元的入口。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"물론이지. 자, 내게 업혀......","JPN":"もちろんいいわよ。ほら、おんぶして……","ENG":"Of course. Now, hop on my back—","TWN":"這當然，來，我來揹妳……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"크아아악!!","JPN":"グアァァッ！！","ENG":"Aaah!","TWN":"啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_STING_BIG"},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"너...... 너 이 자식!","JPN":"テ……テメェ！","ENG":"You... You cursed wench!","TWN":"你……你這傢伙！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"뒤에서 목을 물어뜯다니, 무슨 생각이야?!","JPN":"後ろから首に噛みつきやがった……！　何のつもりよ！？","ENG":"What are you thinking, biting my neck from behind?","TWN":"竟然從背後咬了我的頭，妳是要想什麼？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"내가 너 따위 배신자를 도와 줄 거라고 생각했나?","JPN":"私が貴様のような裏切者に協力するとでも思ったか？","ENG":"Did you think I'd really help a traitor like you?","TWN":"妳以為我會幫妳這種叛徒嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"네 덕분에 저 안에서 아주 좋은 교훈을 하나 배웠다. 알렉스.","JPN":"貴様のおかげで一つ良い教訓が得られたぞ。アレックス。","ENG":"I learned a valuable lesson in there, thanks to you, Alex.","TWN":"多虧了妳，妳讓我學到了一個寶貴的教訓，雅蕾克絲。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"나는 그 동안 내가 원본보다 우월하다는 사실을 증명하려고 무던히도 애썼어.","JPN":"これまで私は己がオリジナルより優れていることを証明するべく、\\n必死に頑張ってきたが……","ENG":"I tried so hard to prove myself superior to my original.","TWN":"為了證明我比本體更為優秀，我不斷地在努力。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"하지만 판단 착오가 하나 있었지.","JPN":"一つだけ判断を間違えていた。","ENG":"But there was one critical error in my judgment.","TWN":"但我在判斷上犯了一個錯。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"바로 쓸모 없는 너희를 계속 부하로 두고 있었던 거다.","JPN":"貴様のような無能な部下を残していたことが間違いだったのだ。","ENG":"That is, I let incompetent fools like you stay as my subordinates.","TWN":"就是讓你們這些沒用的東西當我的部下。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그, 그만둬! 설마 내 힘을 전부 빨아들일 생각이야?!","JPN":"や、やめろ！　まさか私の力を全部吸い取る気！？","ENG":"S-stop it! Are you really going to suck in all my power?","TWN":"住、住手！妳難道想吸收我所有力量嗎？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"나도 그때 널 완전히 잡아먹지는 않았다고!","JPN":"私はあの時、アンタを完全に喰い尽くしたりはしなかったわ！","ENG":"I didn't devour you completely back then either!","TWN":"我當時可沒有完全吃掉你呀！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그래서 이렇게 당하는 신세가 된 거지. 좋은 가르침이 됐어.","JPN":"だから今こうしてやられるというわけだ。実に良い反面教師だな。","ENG":"And that is precisely why you're in this situation. It was a valuable lesson.","TWN":"就是因為這樣，妳現在才會被我吃掉。真是個寶貴的教訓。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"흐음. 저기 네 몸 안의 이터니움이 느껴지는군.","JPN":"ふむ。貴様の体内のエタニウムを感じるぞ。","ENG":"Hmm... I can sense the Eternium deep within your body.","TWN":"嗯，我感受到了妳身體裡的永恆之金。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"저것까지 먹어버리면 넌 영원히 소멸해 버리겠지?","JPN":"これさえ喰い尽くしてしまえば、貴様は永遠に消滅してしまうだろうな？","ENG":"I bet you will be extinguished forever if I devour that too?","TWN":"如果我把它也吃掉，妳就會永遠消失吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"아, 안 돼......! 그것만은......!","JPN":"ダ、ダメ……！　それだけは……！","ENG":"N-no! Anything but that!","TWN":"啊，不……！就只有這個，求求妳……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"너무 억울해 할 필요 없어.","JPN":"そう怖がることはないさ。","ENG":"There's no need to be so dismayed.","TWN":"不需要覺得冤枉。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"살아남은 다른 대원들도 모조리 잡아먹고 지옥으로 보내줄 테니까.","JPN":"生き残った他の隊員も喰い尽くして、\\n皆仲良く地獄へ送ってやる。","ENG":"You will soon be reunited with everyone else in hell, once I devour them all too.","TWN":"我會把剩下的隊員們一個個吃掉，送他們下地獄陪妳的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그래. 애초에 처음부터 이래야 했어.","JPN":"ああ、そうとも。最初からこうするべきだったのだ。","ENG":"That's right. I should've done this from the very beginning.","TWN":"是啊，從一開始就應該這樣做。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"부대니, 대원들이니...... 그 따위 <color=#ffd34c>인간적</color>인 것에 연연해서 문제였던 거야.","JPN":"部隊だの、隊員たちだの……\\nそういった<color=#ffd34c>人間じみた</color>ことにこだわったことが間違いだった。","ENG":"Division, troops... My attachment to such <color=#ffd34c>human</color> things was the root of all my problems.","TWN":"什麼部隊，什麼隊員……根本就不應該執著於這些<color=#ffd34c>人類的</color>東西。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"침식체라면 침식체답게 행동해야지! 안 그런가, 부관?!","JPN":"侵食体なら侵食体らしく振る舞わねばな！　そうは思わぬか？\\nなぁ！　副官殿！","ENG":"A C.O. ought to act like one! Don't you think so, my adjutant?","TWN":"侵蝕體應該像個侵蝕體行動！對吧，副官？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그만둬! 그만두라고!!","JPN":"やめて！　……やめろォォ！！","ENG":"Stop it! Stop!","TWN":"住手！住手！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"끄아아아악......!","JPN":"グアアアァッ……！","ENG":"Gaaahh!","TWN":"啊啊啊啊啊……！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};